create or replace function public.can_access_hr_domain(p_project_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select coalesce(
    public.project_role_for_profile(p_project_id, auth.uid()) in ('owner', 'co_owner'),
    false
  );
$$;

revoke all on function public.can_access_hr_domain(uuid) from public;
grant execute on function public.can_access_hr_domain(uuid) to authenticated;

create or replace function public.get_hr_operational_summary(
  p_project_id uuid,
  p_limit integer default 200,
  p_offset integer default 0
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_limit integer := least(greatest(coalesce(p_limit, 200), 1), 500);
  v_offset integer := greatest(coalesce(p_offset, 0), 0);
  v_allowed boolean;
  v_finance text;
  v_hr_items jsonb := '[]'::jsonb;
begin
  v_allowed := public.can_access_project(p_project_id);

  if not v_allowed then
    return jsonb_build_object(
      'hr_items', '[]'::jsonb
    );
  end if;

  if not public.can_access_hr_domain(p_project_id) then
    return jsonb_build_object(
      'hr_items', '[]'::jsonb
    );
  end if;

  v_finance := public.effective_finance_visibility(p_project_id);

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'hr_item_id', rows.hr_item_id,
        'project_id', rows.project_id,
        'project_stage_id', rows.project_stage_id,
        'estimate_work_id', rows.estimate_work_id,
        'estimate_resource_line_id', rows.estimate_resource_line_id,
        'estimate_resource_line_resource_type', rows.estimate_resource_line_resource_type,
        'task_id', rows.task_id,
        'title', rows.title,
        'description', rows.description,
        'compensation_type', rows.compensation_type,
        'planned_cost_cents',
          case when v_finance = 'detail' then rows.planned_cost_cents else null end,
        'actual_cost_cents',
          case when v_finance = 'detail' then rows.actual_cost_cents else null end,
        'status', rows.status,
        'start_at', rows.start_at,
        'end_at', rows.end_at,
        'created_by', rows.created_by,
        'created_at', rows.created_at,
        'updated_at', rows.updated_at,
        'assignees', rows.assignees
      )
      order by rows.updated_at desc, rows.hr_item_id
    ),
    '[]'::jsonb
  )
  into v_hr_items
  from (
    select
      hi.id as hr_item_id,
      hi.project_id,
      hi.project_stage_id,
      hi.estimate_work_id,
      hi.estimate_resource_line_id,
      erl.resource_type as estimate_resource_line_resource_type,
      hi.task_id,
      hi.title,
      hi.description,
      hi.compensation_type,
      hi.planned_cost_cents,
      hi.actual_cost_cents,
      hi.status,
      hi.start_at,
      hi.end_at,
      hi.created_by,
      hi.created_at,
      hi.updated_at,
      (
        select coalesce(jsonb_agg(
          jsonb_build_object(
            'profile_id', hia.profile_id,
            'role_label', hia.role_label
          )
        ), '[]'::jsonb)
        from public.hr_item_assignees hia
        where hia.hr_item_id = hi.id
      ) as assignees
    from public.hr_items hi
    left join public.estimate_resource_lines erl
      on erl.id = hi.estimate_resource_line_id
    where hi.project_id = p_project_id
    order by hi.updated_at desc, hi.id
    offset v_offset
    limit v_limit
  ) rows;

  return jsonb_build_object(
    'hr_items', v_hr_items
  );
end;
$$;

revoke all on function public.get_hr_operational_summary(uuid, integer, integer) from public;
grant execute on function public.get_hr_operational_summary(uuid, integer, integer) to authenticated;
